#include <nthread-impl.h>
#include "subasta.h"

typedef struct Oferta {
    nThread th;
    double precio;
    int resultado;  // -1: pendiente, 0: FALSE, 1: TRUE
    struct Oferta *sig;
} Oferta;

struct subasta {
    int n;           // Number of items
    int count;       // Current number of bidders
    int cerrada;     // 1 if closed
    Oferta *ofertas;  // Sorted linked list (descending by price)
};

nSubasta nNuevaSubasta(int n) {
    nSubasta s = (nSubasta) nMalloc(sizeof(struct subasta));
    s->n = n;
    s->count = 0;
    s->cerrada = 0;
    s->ofertas = NULL;
    return s;
}

void nDestruirSubasta(nSubasta s) {
    // Free any remaining offers
    Oferta *curr = s->ofertas;
    while (curr != NULL) {
        Oferta *next = curr->sig;
        nFree(curr);
        curr = next;
    }
    nFree(s);
}

// Insert offer in sorted position (descending price)
// For equal prices, insert after existing ones (FIFO for same price)
static void insertarOferta(Oferta **lista, Oferta *of) {
    if (*lista == NULL || (*lista)->precio < of->precio) {
        of->sig = *lista;
        *lista = of;
    } else {
        Oferta *curr = *lista;
        while (curr->sig != NULL && curr->sig->precio >= of->precio) {
            curr = curr->sig;
        }
        of->sig = curr->sig;
        curr->sig = of;
    }
}

// Remove and return the last offer (lowest price)
static Oferta *quitarMenor(Oferta **lista) {
    if (*lista == NULL) return NULL;
    if ((*lista)->sig == NULL) {
        Oferta *of = *lista;
        *lista = NULL;
        return of;
    }
    Oferta *curr = *lista;
    while (curr->sig->sig != NULL) {
        curr = curr->sig;
    }
    Oferta *of = curr->sig;
    curr->sig = NULL;
    return of;
}

// Remove a specific offer from the list
static void quitarOferta(Oferta **lista, Oferta *of) {
    if (*lista == NULL) return;
    if (*lista == of) {
        *lista = of->sig;
        return;
    }
    Oferta *curr = *lista;
    while (curr->sig != NULL && curr->sig != of) {
        curr = curr->sig;
    }
    if (curr->sig == of) {
        curr->sig = of->sig;
    }
}

int nOfrecer(nSubasta s, double oferta) {
    START_CRITICAL

    if (s->cerrada) {
        END_CRITICAL
        return FALSE;
    }

    // Create offer entry
    Oferta *of = (Oferta *) nMalloc(sizeof(Oferta));
    of->th = nSelf();
    of->precio = oferta;
    of->resultado = -1;
    of->sig = NULL;

    // Insert in sorted order
    insertarOferta(&s->ofertas, of);
    s->count++;

    // If oversubscribed, kick out lowest bidders
    while (s->count > s->n) {
        Oferta *perdedor = quitarMenor(&s->ofertas);
        s->count--;
        perdedor->resultado = FALSE;

        if (perdedor == of) {
            // This thread loses immediately
            nFree(of);
            END_CRITICAL
            return FALSE;
        }

        // Wake up the losing thread
        setReady(perdedor->th);
        // Note: we don't schedule() here, we wait until we're about to suspend
    }

    // Check if we need to schedule (to allow kicked-out threads to run)
    // Actually, we should schedule to let losers run
    // But if we schedule here, we might never come back if auction closes

    // Wait for auction to close or to be kicked out
    if (of->resultado == -1) {
        suspend(WAIT_SUBASTA);
        schedule();
    }

    // Woken up - read result
    int res = of->resultado;

    // Remove from list (if still there)
    quitarOferta(&s->ofertas, of);
    nFree(of);

    END_CRITICAL
    return res;
}
