#include <nthread-impl.h>
#include "subasta.h"

// =============================================================
// Implemente a partir de aca el tipo Subasta, puede agregar
// funciones, estructuras o variables que considere necesarias
// =============================================================

// Structure for each offer/bid
typedef struct Oferta {
    nThread th;          // Thread that made the offer
    double precio;       // Offered price
    int resultado;       // -1=pendiente, 0=FALSE (pierde), 1=TRUE (gana)
    struct Oferta *sig;  // Next in sorted linked list
} Oferta;

struct subasta {
    int n;               // Number of items being auctioned
    int count;           // Current number of active offers
    int cerrada;         // 1 if the auction has been closed
    Oferta *ofertas;     // Sorted linked list (descending by price)
};

// Insert an offer in sorted position (descending by price).
// For equal prices, insert after existing ones (FIFO for ties).
static void insertarOferta(Oferta **lista, Oferta *of) {
    if (*lista == NULL || (*lista)->precio < of->precio) {
        of->sig = *lista;
        *lista = of;
    } else {
        Oferta *curr = *lista;
        while (curr->sig != NULL && curr->sig->precio >= of->precio) {
            curr = curr->sig;
        }
        of->sig = curr->sig;
        curr->sig = of;
    }
}

// Remove and return the last offer (lowest price).
static Oferta *quitarMenor(Oferta **lista) {
    if (*lista == NULL) return NULL;
    if ((*lista)->sig == NULL) {
        Oferta *of = *lista;
        *lista = NULL;
        return of;
    }
    Oferta *curr = *lista;
    while (curr->sig->sig != NULL) {
        curr = curr->sig;
    }
    Oferta *of = curr->sig;
    curr->sig = NULL;
    return of;
}

// Remove a specific offer from the list (safe if not present).
static void quitarOferta(Oferta **lista, Oferta *of) {
    if (*lista == NULL) return;
    if (*lista == of) {
        *lista = of->sig;
        return;
    }
    Oferta *curr = *lista;
    while (curr->sig != NULL && curr->sig != of) {
        curr = curr->sig;
    }
    if (curr->sig == of) {
        curr->sig = of->sig;
    }
}

// =============================================================
// Public API
// =============================================================

nSubasta nNuevaSubasta(int n) {
    nSubasta s = (nSubasta) nMalloc(sizeof(struct subasta));
    s->n      = n;
    s->count  = 0;
    s->cerrada = 0;
    s->ofertas = NULL;
    return s;
}

void nDestruirSubasta(nSubasta s) {
    // Free any remaining offers (should not happen in normal flow)
    Oferta *curr = s->ofertas;
    while (curr != NULL) {
        Oferta *next = curr->sig;
        nFree(curr);
        curr = next;
    }
    nFree(s);
}

int nOfrecer(nSubasta s, double oferta) {
    START_CRITICAL

    // If auction already closed, reject the offer
    if (s->cerrada) {
        END_CRITICAL
        return FALSE;
    }

    // Create offer entry
    Oferta *of = (Oferta *) nMalloc(sizeof(Oferta));
    of->th       = nSelf();
    of->precio   = oferta;
    of->resultado = -1;
    of->sig      = NULL;

    // Insert in sorted order (descending by price)
    insertarOferta(&s->ofertas, of);
    s->count++;

    // If we have more than n offers, the lowest one loses
    if (s->count > s->n) {
        Oferta *perdedor = quitarMenor(&s->ofertas);
        s->count--;
        perdedor->resultado = FALSE;

        if (perdedor == of) {
            // This thread loses immediately
            nFree(of);
            END_CRITICAL
            return FALSE;
        }

        // Wake up the losing thread
        setReady(perdedor->th);
    }

    // Wait for the auction to close or to be kicked out
    if (of->resultado == -1) {
        suspend(WAIT_SUBASTA);
        schedule();
    }

    // Read result
    int res = of->resultado;

    // Remove from list (safe no-op if already removed)
    quitarOferta(&s->ofertas, of);
    nFree(of);

    END_CRITICAL
    return res;
}

double nAdjudicar(nSubasta s, int *punid) {
    START_CRITICAL

    s->cerrada = 1;

    double total = 0;
    int ganadores = 0;

    // Winners: top n bidders (or all if fewer than n)
    Oferta *curr = s->ofertas;
    while (curr != NULL && ganadores < s->n) {
        curr->resultado = TRUE;
        setReady(curr->th);
        total += curr->precio;
        ganadores++;
        curr = curr->sig;
    }

    // Losers: remaining bidders (if any)
    while (curr != NULL) {
        curr->resultado = FALSE;
        setReady(curr->th);
        curr = curr->sig;
    }

    // Compute unsold units
    if (punid != NULL) {
        *punid = (ganadores < s->n) ? (s->n - ganadores) : 0;
    }

    // Yield to allow woken threads to run
    schedule();

    END_CRITICAL
    return total;
}

